#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, k;
        scanf("%d %d", &N, &k);
        long long A[N];
        for (int i = 0; i < N; i++) {
            scanf("%lld", &A[i]);
        }
        long long maxProduct = -1;
        int partitionPoint = -1;
        for (int i = 1; i < N; i++) {
            long long leftSum = 0;
            long long rightSum = 0;
            for (int j = 0; j < i; j++) {
                leftSum += (long long)k * A[j];
            }
            for (int j = i; j < N; j++) {
                rightSum += (long long)k * A[j];
            }
            long long product = leftSum * rightSum;
            if (product > maxProduct) {
                maxProduct = product;
                partitionPoint = i;
            }
        }
        printf("%d\n", partitionPoint);
    }
    return 0;
}

